mapper.select:
select

from test_report_record
where id = #{id,jdbcType=BIGINT}

SELECT distinct t1.id, t1.entrustment_id, t1.entrust_id, t1.report_code, t1.sample_name, t1.required_completion_time, t1.number, t1.issuer_time, t1.seal_type, t1.sealer, t1.seal_time, t2.product_id, t1.qys_docment_id, t1.qys_state, t1.contract_id, t1.sign_url, t1.type, t1.type reportTypeStatus FROM test_report_record t1 LEFT JOIN test_product t2 ON t1.sample_name = t2.product_name LEFT JOIN test_task t3 ON t1.entrustment_id = t3.entrustment_id or t1.entrust_id = t3.entrustment_id WHERE t1.state =6
AND t3.dept_id IN
#{id}
AND t1.report_code like CONCAT('%',#{search},'%')
AND t1.qys_state = #{state}
AND t1.report_type = #{reportType}
AND t1.type = #{reportTypeStatus}
order by t1.issuer_time desc

mapper.update:
update test_report_record
set seal_url=#{url},state = '7'
where id = #{id}

mapper.select:
select report_url, seal_url, sign_url
from test_report_record
where report_code = #{reportCode}

select entrustment_id
from test_report_record
where report_code = #{reportCode}

SELECT

FROM test_report_record
where entrustment_id = #{entrustId,jdbcType=BIGINT}

SELECT

FROM test_report_record
where entrust_id = #{entrustId,jdbcType=BIGINT}

SELECT

FROM test_report_record
where id = #{recordId,jdbcType=BIGINT}

SELECT

FROM test_report_record
where task_id = #{taskId,jdbcType=BIGINT}

SELECT id, category, entrustment_id As entrustmentId, report_code, sample_name, number, report_type, report_time, addressee, waybill, email, report_manager, operate_time, report_mailing_address, report_phone, type as reportTypeStatus FROM test_report_record WHERE 1=1
AND state = 7
AND state = 8
AND report_code = #{search}
AND report_type = #{reportType}
AND type = #{reportTypeStatus}
order by operate_time desc

SELECT t1.id, t1.report_code, t2.entrustment_no, IFNULL( CONCAT( t2.entrust_category_type, t2.entrustment_no ), t2.entrustment_no ) AS entrustmentNostr, t2.entrust_company, t1.sample_name, t1.number, t1.type, t1.category, t1.report_complete_time, t1.report_url, t1.report_type, t1.report_time, IFNULL(t1.report_mailing_address,t2.address) reportMailingAddress, IFNULL(t1.addressee,t2.addressee) addressee, IFNULL(t1.report_phone,t2.mobile) report_phone, t1.waybill, IFNULL(t1.email,t2.mailbox) email, t1.report_manager FROM test_report_record t1 LEFT JOIN test_entrusted_info t2 ON t1.entrustment_id = t2.id WHERE 1=1
AND t1.state = 7
AND t1.state = 8
AND t1.report_code like CONCAT('%',#{search},'%')
AND t1.report_type = #{reportType}
AND t1.type = #{reportTypeStatus}
AND t1.category = #{category}
order by t1.operate_time desc

SELECT t1.id, t1.report_code, t2.entrustment_no, IFNULL( CONCAT( t2.entrust_category_type, t2.entrustment_no ), t2.entrustment_no ) AS entrustmentNostr, t2.entrust_company, t1.sample_name, t1.number, t1.type, t1.category, t1.report_complete_time, t1.report_url, t1.report_type, t1.report_time, IFNULL(t1.report_mailing_address,t2.address) reportMailingAddress, IFNULL(t1.addressee,t2.addressee) addressee, IFNULL(t1.report_phone,t2.mobile) report_phone, t1.waybill, IFNULL(t1.email,t2.mailbox) email, t1.report_manager FROM test_report_record_mid t1 LEFT JOIN test_entrusted_info t2 ON t1.entrust_id = t2.id WHERE 1=1
AND t1.state = 7
AND t1.state = 8
AND t1.report_code like CONCAT('%',#{search},'%')
AND t1.report_type = #{reportType}
AND t1.type = #{reportTypeStatus}
AND t1.category = #{category}
order by t1.operate_time desc

SELECT t1.id, t1.entrustment_id, t1.report_code, t1.sample_name, t1.required_completion_time, t1.number, t1.issuer_time, t1.seal_type, t1.sealer, t1.seal_time, t2.product_id, t1.qys_docment_id, t1.qys_state, t1.contract_id, t1.sign_url, t1.type reportTypeStatus FROM test_report_record t1 LEFT JOIN test_product t2 ON t1.sample_name = t2.product_name LEFT JOIN test_task t3 ON t1.entrustment_id = t3.entrustment_id WHERE t1.state =6
AND t3.dept_id IN
#{id}

(SELECT t1.id, t1.report_code, t2.entrustment_no, IFNULL( CONCAT( t2.entrust_category_type, t2.entrustment_no ), t2.entrustment_no ) AS entrustmentNostr, t2.entrust_company, t1.sample_name, t1.number, t1.type, t1.category, t1.report_complete_time, t1.report_url, t1.report_type, t1.report_time, IFNULL(t1.report_mailing_address,t2.address) reportMailingAddress, IFNULL(t1.addressee,t2.addressee) addressee, IFNULL(t1.report_phone,t2.mobile) report_phone, t1.waybill, IFNULL(t1.email,t2.mailbox) email, t1.report_manager, t1.operate_time FROM test_report_record t1 LEFT JOIN test_entrusted_info t2 ON t1.entrustment_id = t2.id WHERE 1=1
AND t1.state = 7
AND t1.state = 8
AND t1.report_code like CONCAT('%',#{search},'%')
AND t1.report_type = #{reportType}
AND t1.type = #{reportTypeStatus}
AND t1.category = #{category}
) UNION ( SELECT t1.id, t1.report_code, t2.entrustment_no, IFNULL( CONCAT( t2.entrust_category_type, t2.entrustment_no ), t2.entrustment_no ) AS entrustmentNostr, t2.entrust_company, t1.sample_name, t1.number, t1.type, t1.category, t1.report_complete_time, t1.report_url, t1.report_type, t1.report_time, IFNULL(t1.report_mailing_address,t2.address) reportMailingAddress, IFNULL(t1.addressee,t2.addressee) addressee, IFNULL(t1.report_phone,t2.mobile) report_phone, t1.waybill, IFNULL(t1.email,t2.mailbox) email, t1.report_manager, t1.operate_time FROM test_report_record_mid t1 LEFT JOIN test_entrusted_info t2 ON t1.entrust_id = t2.id WHERE 1=1
AND t1.state = 7
AND t1.state = 8
AND t1.report_code like CONCAT('%',#{search},'%')
AND t1.report_type = #{reportType}
AND t1.type = #{reportTypeStatus}
AND t1.category = #{category}
) order by operate_time desc
